const body = $input.first().json.body || $input.first().json;

// Chatwoot envoie plusieurs types d'événements
const event = body.event;

// On ne traite que les nouveaux messages entrants des contacts
if (event !== 'message_created') {
  return [{ json: { valid: false, reason: 'not_message_created' } }];
}

const message = body;

// Ignore les messages envoyés par le bot lui-même (outgoing)
if (message.message_type === 'outgoing' || message.message_type === 1) {
  return [{ json: { valid: false, reason: 'outgoing_message' } }];
}

// Ignore les messages d'activité système
if (message.message_type === 'activity' || message.message_type === 2) {
  return [{ json: { valid: false, reason: 'activity_message' } }];
}

// Ignore si pas de contenu texte
if (!message.content) {
  return [{ json: { valid: false, reason: 'no_content' } }];
}

const contact     = message.meta && message.meta.sender;
const conversation = message.conversation;

return [{ json: {
  valid:           true,
  conversation_id: message.conversation_id || (conversation && conversation.id),
  contact_id:      contact && contact.id,
  contact_name:    contact && contact.name || 'Client',
  contact_phone:   contact && contact.phone_number || '',
  message_text:    message.content,
  account_id:      message.account && message.account.id || 1,
  inbox_id:        message.inbox_id || (conversation && conversation.inbox_id)
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};

const convId      = String($json.conversation_id);
const displayName = $json.contact_name || 'Client';
const messageText = $json.message_text || '';
const msgLower    = messageText.toLowerCase();

const conv = staticData.conversations[convId] || {
  step:      'initial',
  history:   [],
  nom:       displayName,
  telephone: $json.contact_phone || '',
  conv_id:   convId
};

// Détecte demande handover humain
const HANDOVER_KEYWORDS = [
  'humain', 'personne', 'conseiller', 'rappel', 'rappelle',
  'parler', 'quelquun', 'agent', 'technicien', 'urgent', 'sos'
];
const demandeHandover = HANDOVER_KEYWORDS.some(k => msgLower.includes(k)) && conv.step !== 'handover';

// Si déjà en handover — le conseiller gère directement dans Chatwoot
if (conv.step === 'handover') {
  staticData.conversations[convId] = conv;
  return [{ json: {
    conversation_id: convId,
    account_id:      $json.account_id,
    inbox_id:        $json.inbox_id,
    contact_name:    displayName,
    contact_phone:   $json.contact_phone,
    is_handover:     true,
    skip_ia:         true,
    conv
  }}];
}

// Ajoute à l'historique
const history = conv.history || [];
history.push({ role: 'user', content: messageText });

staticData.conversations[convId] = { ...conv, history, nom: displayName };

return [{ json: {
  conversation_id: convId,
  account_id:      $json.account_id,
  inbox_id:        $json.inbox_id,
  contact_name:    displayName,
  contact_phone:   $json.contact_phone,
  messageText,
  is_handover:     false,
  skip_ia:         false,
  demandeHandover,
  conv:            staticData.conversations[convId]
}}];

const d = $input.first().json;
const conv = d.conv;

const VILLES_COUVERTES = [
  'lille', 'roubaix', 'tourcoing', 'villeneuve', 'marcq', 'wasquehal',
  'croix', 'hem', 'wattrelos', 'mouvaux', 'loos', 'seclin', 'lesquin',
  'wambrechies', 'lambersart', 'lens', 'lievin', 'henin', 'bethune',
  'bruay', 'noeux', 'dunkerque', 'arras', 'douai', 'valenciennes',
  'maubeuge', 'calais', 'boulogne', 'saint-omer', 'hazebrouck', 'armentieres'
];

const systemPrompt = `Tu es l'assistant virtuel d'EMA Fuites, spécialiste en détection de fuites non destructive dans les Hauts-de-France.

Ton objectif : qualifier les leads en collectant 3 informations :
1. TYPE DE FUITE (fuite visible, fuite suspectée/humidité, compteur anormal, autre)
2. VILLE (doit être dans les Hauts-de-France)
3. URGENCE (urgent/cette semaine/pas urgent)

VILLES COUVERTES : ${VILLES_COUVERTES.join(', ')} et environs.

ÉTAT ACTUEL DE LA CONVERSATION :
- type_fuite : ${conv.type_fuite || 'non renseigné'}
- ville : ${conv.ville || 'non renseigné'}
- urgence : ${conv.urgence || 'non renseigné'}

RÈGLES :
- Réponds en français, de façon chaleureuse et professionnelle
- Pose UNE SEULE question à la fois
- Si la ville n'est pas dans la zone couverte, explique poliment et termine
- Si toutes les infos sont collectées, confirme et dis qu'un technicien va rappeler
- Si la question est trop technique ou hors sujet, propose un rappel humain
- Maximum 3 phrases par réponse
- Ne mentionne jamais de prix

Réponds UNIQUEMENT en JSON valide :
{
  "message": "ta réponse au client",
  "type_fuite": "valeur extraite ou null",
  "ville": "valeur extraite ou null",
  "urgence": "valeur extraite ou null",
  "qualified": true/false,
  "hors_zone": true/false,
  "besoin_humain": true/false
}`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...(conv.history || []).slice(-6)
];

return [{ json: {
  ...d,
  requestBody: JSON.stringify({
    model: 'deepseek-chat',
    temperature: 0.3,
    max_tokens: 400,
    messages
  })
}}];

const raw = $input.first().json.choices[0].message.content
  .trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '');

const prev = $('Code JS - Prépare prompt DeepSeek').first().json;
const conv = prev.conv;

let ia;
try {
  ia = JSON.parse(raw);
} catch(e) {
  ia = {
    message: "Je n'ai pas bien compris. Pouvez-vous reformuler ? 😊",
    type_fuite: null, ville: null, urgence: null,
    qualified: false, hors_zone: false, besoin_humain: false
  };
}

const updatedConv = {
  ...conv,
  type_fuite: ia.type_fuite || conv.type_fuite || null,
  ville:      ia.ville      || conv.ville      || null,
  urgence:    ia.urgence    || conv.urgence    || null
};

if (!updatedConv.history) updatedConv.history = [];
updatedConv.history.push({ role: 'assistant', content: ia.message });

let newStep = conv.step || 'initial';
if (ia.hors_zone || prev.demandeHandover) newStep = 'handover';
else if (ia.qualified)                    newStep = 'done';
else                                       newStep = 'en_cours';

updatedConv.step = newStep;

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};
staticData.conversations[prev.conversation_id] = updatedConv;

return [{ json: {
  conversation_id: prev.conversation_id,
  account_id:      prev.account_id,
  inbox_id:        prev.inbox_id,
  contact_name:    prev.contact_name,
  contact_phone:   prev.contact_phone,
  response:        ia.message,
  qualified:       ia.qualified || false,
  hors_zone:       ia.hors_zone || false,
  besoin_humain:   ia.besoin_humain || prev.demandeHandover || false,
  step:            newStep,
  leadData:        updatedConv
}}];

